previewCss:
.darma-loader-darma-custom-626 {color: var(--loader-color, #0f766e);
  --loader-secondary-color: var(--loader-secondary-color, #5eead4);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 40px;
   aspect-ratio: 1;
   outline: 2px solid currentColor;
   background: radial-gradient(farthest-side,currentColor 90%,#0000) 0 0/8px 8px no-repeat, conic-gradient(from 90deg at 10px 10px,#0000 90deg,currentColor 0), conic-gradient(from -90deg at 30px 30px,#0000 90deg,currentColor 0);
   animation: darma-loader-darma-custom-626-l3 1.5s infinite;
}
@keyframes darma-loader-darma-custom-626-l3  {
  0% {background-position:0 0 ;
  clip-path:circle(15px at left 4px top 4px)}
25% {background-position:100% 0 ;
  clip-path:circle(15px at right 4px top 4px)}
50% {background-position:100% 100%;
  clip-path:circle(15px at right 4px bottom 4px)}
75% {background-position:0 100%;
  clip-path:circle(15px at left 4px bottom 4px)}
100% {background-position:0 0 ;
  clip-path:circle(15px at left 4px top 4px)}
}

